SELECT id, username, real_name, login_ip, browser, os, login_status, login_at FROM sys_login_log WHERE 1 = 1
AND (username LIKE CONCAT('%', #{keyword}, '%') OR real_name LIKE CONCAT('%', #{keyword}, '%'))
AND login_status = #{loginStatus}
ORDER BY id DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(1) FROM sys_login_log WHERE 1 = 1
AND (username LIKE CONCAT('%', #{keyword}, '%') OR real_name LIKE CONCAT('%', #{keyword}, '%'))
AND login_status = #{loginStatus}

SELECT id, module_name, biz_type, operation_type, operator_name, operator_ip, result_status, created_at FROM sys_operation_log WHERE 1 = 1
AND module_name = #{moduleName}
AND result_status = #{resultStatus}
AND ( operator_name LIKE CONCAT('%', #{keyword}, '%') OR request_uri LIKE CONCAT('%', #{keyword}, '%') OR biz_type LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY id DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(1)
FROM sys_operation_log
WHERE 1 = 1

    AND module_name = #{moduleName}


    AND result_status = #{resultStatus}


    AND (
        operator_name LIKE CONCAT('%', #{keyword}, '%')
        OR request_uri LIKE CONCAT('%', #{keyword}, '%')
        OR biz_type LIKE CONCAT('%', #{keyword}, '%')
    )
